import{_ as n,o as s,c as e,a0 as o}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"📦 買家交易與預約指南","description":"","frontmatter":{},"headers":[],"relativePath":"Shop-Transaction.md","filePath":"Shop-Transaction.md"}'),l={name:"Shop-Transaction.md"};function r(t,a,i,p,c,d){return s(),e("div",null,[...a[0]||(a[0]=[o(`<h1 id="📦-買家交易與預約指南" tabindex="-1">📦 買家交易與預約指南 <a class="header-anchor" href="#📦-買家交易與預約指南" aria-label="Permalink to &quot;📦 買家交易與預約指南&quot;">​</a></h1><p>本章節說明普通玩家（顧客）如何與箱子商店進行交易，以及當商店物資缺貨時的預約掛單與自動派貨流程。</p><hr><h2 id="_1-🔍-觸發交易選單-sign-control-panel" tabindex="-1">1. 🔍 觸發交易選單 (Sign Control Panel) <a class="header-anchor" href="#_1-🔍-觸發交易選單-sign-control-panel" aria-label="Permalink to &quot;1. 🔍 觸發交易選單 (Sign Control Panel)&quot;">​</a></h2><p>當顧客對著任何已註冊商店的<strong>告示牌 (Sign)</strong> 按下**【右鍵】**時，系統會在聊天欄單獨彈出您的個人交易面板（此內容為私密訊息，其他玩家無法看見）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>§6=================== 商店交易 ===================</span></span>
<span class="line"><span>§f商品名稱: 鑽石</span></span>
<span class="line"><span>§f商店主人: Yanggu</span></span>
<span class="line"><span>§f商品預覽: [物品預覽] (滑鼠移上去可查看物品屬性說明)</span></span>
<span class="line"><span>§f耐久度資訊: 剩餘 100% 點耐久度。</span></span>
<span class="line"><span>§a[出售商品] -&gt; 單價: §e$100.0§f (庫存: 64)</span></span>
<span class="line"><span>§6---------------------------------------------</span></span>
<span class="line"><span>§e★ 在聊天室中輸入你想要購買的數量，您可以購買 64 個。</span></span>
<span class="line"><span>§f- 輸入想要購買的數量（如 10）開始向商店購買商品。</span></span>
<span class="line"><span>§f- 輸入「all」一鍵購買全部庫存。</span></span>
<span class="line"><span>§f- 輸入「cancel」或「取消」結束交易。</span></span>
<span class="line"><span>§6============================================</span></span></code></pre></div><h3 id="⏳-30-秒輸入時間限制" tabindex="-1">⏳ 30 秒輸入時間限制 <a class="header-anchor" href="#⏳-30-秒輸入時間限制" aria-label="Permalink to &quot;⏳ 30 秒輸入時間限制&quot;">​</a></h3><ul><li>顧客此時會進入 <strong>30 秒交易鎖定狀態</strong>。</li><li>在此狀態下，您發送的下一條聊天訊息會被系統直接接收處理，不會發送到公開頻道上，其他玩家不會看見。</li><li>若輸入 <code>cancel</code>、<code>取消</code>，或者在 30 秒內未發送任何訊息，系統會自動退出交易模式。</li></ul><hr><h2 id="_2-🛒-購買商品" tabindex="-1">2. 🛒 購買商品 <a class="header-anchor" href="#_2-🛒-購買商品" aria-label="Permalink to &quot;2. 🛒 購買商品&quot;">​</a></h2><ol><li>在交易模式下，直接在聊天欄輸入想要購買的數量（如：<code>16</code>），或者發送 <code>all</code>。</li><li><strong>購買安全檢查</strong>： <ul><li>您的金幣餘額是否足夠支付總額。</li><li>商店箱子中是否有足夠的庫存。</li><li>您的背包是否有足夠的格子來存放物品。</li></ul></li><li><strong>交易完成</strong>：系統會扣除您的餘額，並在自動扣除 <strong>5% 的印花稅</strong> 後，將剩餘的 95% 金幣存入商店的營收儲存庫，同時自動將商品放入您的背包。</li><li><strong>回饋音效</strong>：交易成功的瞬間，您的耳邊會響起輕快的 <strong>「叮」</strong> 一聲（經驗值球拾取音效），代表交易順利完成。</li></ol><blockquote><p><strong>⚖️ 5% 交易印花稅機制</strong> 所有玩家箱子商店的交易成交時，系統會自動徵收 <strong>5% 印花稅</strong>。</p><ul><li>這 5% 的印花稅會被系統<strong>直接永久銷毀</strong>（從伺服器金幣總流通量中永久移除），不會流向任何管理員或玩家。</li><li>交易收據會清晰列出「商品總價」、「5% 印花稅扣除額」以及「店主實得營收」。</li></ul></blockquote><hr><h2 id="📝-3-缺貨預約訂單機制-pre-order-reservations" tabindex="-1">📝 3. 缺貨預約訂單機制 (Pre-order Reservations) <a class="header-anchor" href="#📝-3-缺貨預約訂單機制-pre-order-reservations" aria-label="Permalink to &quot;📝 3. 缺貨預約訂單機制 (Pre-order Reservations)&quot;">​</a></h2><p>當商店商品賣完（庫存為 0）時，顧客可以發起<strong>預付款預約</strong>：</p><h3 id="預付款預約流程" tabindex="-1">預付款預約流程 <a class="header-anchor" href="#預付款預約流程" aria-label="Permalink to &quot;預付款預約流程&quot;">​</a></h3><ol><li>顧客右鍵點擊告示牌，進入交易模式。</li><li>系統偵測到缺貨，會提示您是否要先付清款項以預約此商品： <code>§b[Craft-Core] §e該商品目前缺貨。您是否要付清款項以預約此商品？</code><code>§f- 輸入您要預約的數量進行預付款預約，或輸入「取消」退出。</code></li><li>輸入數量後，系統會即時扣除顧客帳戶的相應金幣，並由系統安全保管該筆款項。</li></ol><h3 id="系統自動發貨" tabindex="-1">系統自動發貨 <a class="header-anchor" href="#系統自動發貨" aria-label="Permalink to &quot;系統自動發貨&quot;">​</a></h3><ul><li>當商店主人後續對該商店箱子放入貨物進行<strong>補貨</strong>時，系統會自動依預約順序處理。</li><li>貨物會直接從箱子中扣除，並透過<strong>快遞信箱</strong>安全地郵寄給買家（即使買家此時不在線上，下次登入也會收到郵件通知並領取物品）。</li><li>發貨完畢後，店主會正式收到款項。</li></ul><h3 id="取消預約與全額退款" tabindex="-1">取消預約與全額退款 <a class="header-anchor" href="#取消預約與全額退款" aria-label="Permalink to &quot;取消預約與全額退款&quot;">​</a></h3><ul><li>買家若不想繼續等待，可以隨時在遊戲中輸入 <strong>/shop reservations</strong> 查看您目前所有的預約。</li><li>點選對應的取消按鈕，系統會將款項 <strong>100% 全額退還</strong> 給買家，並自動取消預約。</li></ul><hr><h2 id="⭐-4-交易評價系統-shop-ratings" tabindex="-1">⭐ 4. 交易評價系統 (Shop Ratings) <a class="header-anchor" href="#⭐-4-交易評價系統-shop-ratings" aria-label="Permalink to &quot;⭐ 4. 交易評價系統 (Shop Ratings)&quot;">​</a></h2><p>完成交易後，系統會為顧客開啟評分邀請：</p><ol><li>聊天欄會顯示：<code>§e[ 點選此處評分商店 ]</code>。</li><li>點擊該文字會開啟 <strong>30 秒評分輸入時間</strong>，提示您輸入 <code>1</code> 至 <code>5</code> 的整數分數。</li><li>輸入評分後，該商店的平均評分會被更新，並同步展示在 <strong>/shop</strong> 商店清單的資訊中，作為大家挑選商家的指標。</li></ol>`,25)])])}const u=n(l,[["render",r]]);export{g as __pageData,u as default};
